/* eslint-disable */
import proto from '@/utils/sdkapi_pb.js'
import { useWslStore } from '@/store/modules/ws'
import { useXhumanoidFrame } from '@/hooks/useXhumanoidFrame'
const { wrapWithXhumanoidFrame } = useXhumanoidFrame()

class VersionUpgrade {
  constructor() {
    this.request_map = new Map()
  }

  init(files, type, event) {
    this.files = files //inputObj.files[0]
    this.type = type //配置FileReader读取文件的方法
    this.event = event //配置读取文件时需要触发的事件
    this.total = files.size //获取文件大小
    this.step = 1024 * 1024 * 1 //1MB（单片大小/一兆）
    this.loaded = 0 //文件当前读取进度
    this.reader = new FileReader() //实际读取文件的FileReader对象实例
    this.abort = this.reader.abort //中断文件读取（可以通过中断文件读取事件保留切片数据，实现下一次可以在原读取位置继续开始读取）
    this.bindEvent() //绑定FileReader文件读取
    this.readPartFile(this.loaded) //开启读取文件
  }

  setSocketUrl(url) {
    // this.wsUrl = "ws://" + window.location.hostname + ":7123/status";
    this.wsUrl = url
  }

  //给切片读取对象原型上添加FileReader获取读取类型，开启读取文件
  readPartFile(start) {
    // console.log("-------------- ", this.files);
    if (!this.files || !this.files.slice) {
      console.error('read part file error', this.files)
      return
    }
    if (this.files.slice) {
      var file = this.files.slice(start, this.loaded + this.step)
      switch (this.type) {
        // 开始读取指定的 Blob中的内容，根据读取方式不同，result最后返回的数据也不同
        case 'readAsBinaryString': // result属性中将包含所读取文件的原始二进制数据。
          this.reader.readAsBinaryString(file)
          break
        case 'readAsDataURL': // result属性中将包含一个data: URL 格式的 Base64 字符串以表示所读取文件的内容。
          this.reader.readAsDataURL(file)
          break
        case 'readAsArrayBuffer': // result 属性中保存的将是被读取文件的 ArrayBuffer 数据对象。
          this.reader.readAsArrayBuffer(file)
          break
        case 'readAsText': // 一旦完成，result属性中将包含一个字符串以表示所读取的文件内容。
          this.readAsText(file)
          break
      }
    }
  }
  //给切片读取对象原型上绑定FileReader对象事件
  bindEvent() {
    var self = this
    this.reader.onloadstart = function (e) {
      // FileReader.onloadstart 该事件在读取操作开始时触发。
      self.event.loadStart && self.event.loadStart.call(this, e)
    }
    this.reader.onprogress = function (e) {
      // FileReader.onprogress 该事件在读取Blob时触发。
      self.event.progress && self.event.progress.call(this, e)
    }
    this.reader.onload = function (e) {
      // FileReader.onload 该事件在读取操作完成时触发。
      // 切片读取文件有别于非切片读取，切片读取的文件读取状态需要在每个切片读取成功后再刷新读取进度
      self.loaded += e.loaded
      /* self.event.load && */
      self.event.load.call(this, e, self.loaded, self.total)
      // if (self.loaded < self.total) {
      //   self.readPartFile(self.loaded);
      // }
    }
    this.reader.onloadend = function (e) {
      // FileReader.onloadend 该事件在读取操作结束时（要么成功，要么失败）触发。
      self.event.loadend && self.event.loadend.call(this, e)
    }
    this.reader.onabort = function (e) {
      // FileReader.onabort 该事件在读取操作被中断时触发。
      self.event.abort && self.event.abort.call(this, e)
    }
  }

  readFile(socket, file, obj) {
    console.log('read file', file)
    var that = this
    this.package_block_index = 0
    this.request_map = new Map()
    this.request_uid = new Date().getTime() + ''
    this.init(file, 'readAsArrayBuffer', {
      /* var reader = new PartFileReader(file, 'readAsArrayBuffer', { */
      loadStart: function (e) {
        // progressTextObj.innerText = "正在读取文件(0%)...";
        // console.log("reading file 0% ...");
      },
      progress: function (e) {},
      load: function (e, loaded, total) {
        // 如果在读取的基础上写上传的话在这里获取读取成功的文件切片
        // e.target.result //当前文件切片的数据
        var request = new proto.Request()
        request.setCommand(proto.Command.CMD_RUN_VERSION_UPDATE)

        var user_data = that.request_uid + '_' + loaded

        var header = new proto.Header()
        header.setUserdata(user_data)
        request.setHeader(header)

        var param_data = request.addParamData()
        param_data.setKey('cmdtype')
        param_data.setVal('VERSION_UPDATE_UPLOAD_FILE')

        param_data = request.addParamData()
        param_data.setKey('devid')
        param_data.setVal(obj.devid + '')

        param_data = request.addParamData()
        param_data.setKey('devname')
        param_data.setVal(obj.devname + '')

        param_data = request.addParamData()
        param_data.setKey('package_name')
        param_data.setVal(obj.package_name + '')

        param_data = request.addParamData()
        param_data.setKey('package_loaded')
        param_data.setVal(loaded + '')

        param_data = request.addParamData()
        param_data.setKey('package_total')
        param_data.setVal(total + '')

        param_data = request.addParamData()
        param_data.setKey('package_block_index')
        param_data.setVal(that.package_block_index + '')

        param_data = request.addParamData()
        param_data.setKey('package_block_data')
        param_data.setData(new Uint8Array(e.target.result))

        param_data = request.addParamData()
        param_data.setKey('taskid')
        param_data.setVal(that.request_uid)

        if (obj.debug) {
          console.log('reading file: ' + Math.round((loaded / total) * 100))
        }

        obj.cmdtype = 'VERSION_UPDATE_UPLOAD_FILE'
        obj.percent = Math.round((loaded / total) * 100)
        that.request_map.set(user_data, obj)

        //开始上传
        var d = request.serializeBinary()
        socket.send(wrapWithXhumanoidFrame(d))

        if (loaded >= total) {
          console.log('send file end!')
        }
      },
      loadend: function (e) {},
      abort: function (e) {},
      error: function (e) {
        // progressTextObj.innerText = "文件读取出错误(~0v0~)";
      }
    })
  }

  sendWebsocketData(socket, data) {
    if (socket) {
      socket.send(data)
    } else {
      console.error('send websocket data error, socket invalid!')
    }
  }

  openSocket(obj, e) {
    var socket = null
    var that = this
    if (typeof WebSocket == 'undefined') {
      console.log('您的浏览器不支持WebSocket')
    } else {
      console.log('您的浏览器支持WebSocket')
      //实现化WebSocket对象，指定要连接的服务器地址与端口  建立连接
      var socketUrl = this.wsUrl
      // var socketUrl = "ws://localhost:8081/webSocket/" + name;
      console.log(socketUrl)
      if (socket != null) {
        socket.close()
        socket = null
      }

      socket = new WebSocket(socketUrl, 'upgrade')
      //打开事件
      socket.onopen = function () {
        console.log('websocket opened!', obj)
        if (e.onopen) {
          e.onopen(socket, obj)
          // that.readFile(socket, file, obj ? obj : {})
        }
      }

      //获得消息事件
      socket.onmessage = function (msg) {
        that.onWebSocketMessage(socket, msg)
      }
      //关闭事件
      socket.onclose = function () {
        console.log('websocket closed!')
      }
      //发生了错误事件
      socket.onerror = function () {
        console.log('websocket error!')
      }
    }
  }

  onWebSocketMessage(socket, msg) {
    var that = this
    let reader = new FileReader()
    reader.onload = function () {
      var d = proto.Response.deserializeBinary(this.result)
      var j = proto.Response.toObject(null, d)
      if (
        j.command !== proto.Command.CMD_RUN_VERSION_UPDATE &&
        j.command !== proto.Command.CMD_UPDATE_STATUS_UPGRAGE
      ) {
        return
      }
      if (j.command === proto.Command.CMD_RUN_VERSION_UPDATE) {
        if (that.request_map) {
          var obj = that.request_map.get(j.header.userdata)
          if (obj) {
            that.onResponseVersionUpgrade(socket, j, obj)
          }
        }
      } else if (j.command === proto.Command.CMD_UPDATE_STATUS_UPGRAGE) {
        that.onUpdateStatusUpgrade(socket, j)
      }
    }
    reader.readAsArrayBuffer(msg.data)
  }

  onResponseVersionUpgrade(socket, response, obj) {
    var that = this
    if (obj.task === 'VERSION_UPLOAD_FILE') {
      if (response.errorCode === proto.ErrorCode.ERROR_CODE_SUCCESS) {
        if (obj.onEventUploadPercent) {
          obj.onEventUploadPercent(obj, { percent: obj.percent })
        }
        if (that.loaded < that.total) {
          this.readPartFile(that.loaded)
        } else {
          console.log('version upgrade finished response recved')
          if (obj.onEventUploadFinished) {
            obj.onEventUploadFinished(obj, { percent: 100 })
          }
        }
      } else {
        console.error('upload error: ' + response.errorMessage)
        if (obj.onEventErrorMessage) {
          obj.onEventErrorMessage(obj, response)
        }
      }
    } else if (obj.task === 'VERSION_UPGRAD_ING') {
      if (response.errorCode === proto.ErrorCode.ERROR_CODE_SUCCESS) {
        if (obj.cmdtype === 'VERSION_UPDATE_CHECK_STATUS') {
          this.sendRequestStartUpgrade(socket, obj)
        } else if (obj.cmdtype === 'VERSION_UPDATE_START_UPGRADE') {
        }
      } else {
        console.error('upgrade error: ' + response.errorMessage)
        if (obj.onEventErrorMessage) {
          obj.onEventErrorMessage(obj, response)
        }
      }
    }
  }

  onUpdateStatusUpgrade(socket, response) {
    // var that = this
    console.log('++++ onUpdateStatusUpgrade', response)

    //写入 Pinia的ws.js
    const store = useWslStore()
    store.websocketDataReceived({ ...response })

    const taskid = response.header.userdata
    if (!taskid) {
      console.log('---- onUpdateStatusUpgrade: taskid invalid error!')
      return
    }

    //新增升级进度
    const versionInfo = response.versionUpdateResponse || {}
    const {
      //要弹窗alert
      alertMessage,
      alertType,
      //后续要log文本框
      logMessage,
      logType,
      percent,
      upgradeStatus, // OTA_STATUS_FINISHED升级但没重启, OTA_STATUS_SUCCESS升级且重启了
      upgradeFinished, // true
      errorCode, // 只有为ERROR_CODE_SUCCESS才升级成功，别的情况都是有错
      errorMessage //要弹窗error
    } = versionInfo

    var alert_message = ''
    var alert_type = ''
    var error_code = response.errorCode
    var error_message = response.errorMessage

    if (
      response.versionUpdateResponse &&
      response.versionUpdateResponse.alertMessage
    ) {
      alert_message = response.versionUpdateResponse.alertMessage
      alert_type = response.versionUpdateResponse.alertType
    }

    if (this.request_map) {
      // var obj = that.request_map.get(response.header.userdata)
      const obj = this.request_map.get(taskid)
      if (obj) {
        //alert弹窗
        // if (alert_message && alert_message !== '') {
        //   console.log('++++ alert: ' + alert_type + ', ' + alert_message)
        //   if (obj.onEventAlertMessage) {
        //     obj.onEventAlertMessage(obj, response)
        //   }
        // }
        if (alertMessage && obj.onEventAlertMessage) {
          obj.onEventAlertMessage(obj, response)
        }

        //log日志
        // if (logMessage && obj.onEventLogMessage) {
        //   obj.onEventLogMessage(obj, response)
        // }

        //percent进度
        if (typeof percent === 'number' && obj.onEventUpgradeProgress) {
          if (obj.debug) {
            // console.log(`[Debug] upgrading: ${percent}%`)
            console.log(
              `[Debug] upgrading: ${percent}% status: ${upgradeStatus}`
            )
          }
          obj.onEventUpgradeProgress(obj, versionInfo)
        }

        //升级成功
        if (upgradeFinished) {
          // const successCode = proto.ErrorCode.VERSION_UPGRADE_ERROR_CODE_SUCCESS
          const successCode = 'ERROR_CODE_SUCCESS'
          const status = upgradeStatus
          //若errorCode为ERROR_CODE_SUCCESS
          if (errorCode === successCode) {
            if (status === 'OTA_STATUS_FINISHED') {
              if (obj.onUpgradePartialSuccess) {
                obj.onUpgradePartialSuccess(obj, versionInfo)
              }
            } else if (status === 'OTA_STATUS_SUCCESS') {
              if (obj.onUpgradeFullSuccess) {
                obj.onUpgradeFullSuccess(obj, versionInfo)
              }
            }
          }
          //若errorCode不为ERROR_CODE_SUCCESS
          else {
            if (obj.onEventErrorMessage) {
              obj.onEventErrorMessage(obj, response)
            }
          }
        }

        //error错误
        // if (error_code != proto.ErrorCode.ERROR_CODE_SUCCESS) {
        //   console.log(
        //     '++++ error: ' + error_code + ', message: ' + error_message
        //   )
        //   if (obj.onEventErrorMessage) {
        //     obj.onEventErrorMessage(obj, response)
        //   }
        // }
      } else {
        console.error(
          '---- request map data not found: ' + response.header.userdata
        )
      }
    }
  }

  closeSocket(socket) {
    if (socket != null) {
      socket.close()
      socket = null
    }
  }

  sendRequestCheckStatus(socket, obj) {
    var request = new proto.Request()
    request.setCommand(proto.Command.CMD_RUN_VERSION_UPDATE)

    var request_uid = new Date().getTime() + ''
    var user_data = 'CMD_CHECK_STATUS_' + request_uid

    var header = new proto.Header()
    header.setUserdata(user_data)
    request.setHeader(header)

    var cmdtype = 'VERSION_UPDATE_CHECK_STATUS'
    var param_data = request.addParamData()
    param_data.setKey('cmdtype')
    param_data.setVal(cmdtype)

    param_data = request.addParamData()
    param_data.setKey('devid')
    param_data.setVal(obj.devid + '')

    param_data = request.addParamData()
    param_data.setKey('devname')
    param_data.setVal(obj.devname + '')

    param_data = request.addParamData()
    param_data.setKey('package_name')
    param_data.setVal(obj.package_name)

    param_data = request.addParamData()
    param_data.setKey('taskid')
    param_data.setVal(user_data)

    obj.cmdtype = cmdtype
    this.request_map.set(user_data, obj)
    //不用改
    var d = request.serializeBinary()
    socket.send(d)
  }

  sendRequestStartUpgrade(socket, obj) {
    var request = new proto.Request()
    request.setCommand(proto.Command.CMD_RUN_VERSION_UPDATE)

    var request_uid = new Date().getTime() + ''
    var user_data = 'TASK_UPGRADE_' + request_uid

    var header = new proto.Header()
    header.setUserdata(user_data)
    request.setHeader(header)

    var cmdtype = 'VERSION_UPDATE_START_UPGRADE'
    var param_data = request.addParamData()
    param_data.setKey('cmdtype')
    param_data.setVal(cmdtype)

    param_data = request.addParamData()
    param_data.setKey('devid')
    param_data.setVal(obj.devid + '')

    param_data = request.addParamData()
    param_data.setKey('devname')
    param_data.setVal(obj.devname + '')

    param_data = request.addParamData()
    param_data.setKey('package_name')
    param_data.setVal(obj.package_name)

    param_data = request.addParamData()
    param_data.setKey('taskid')
    param_data.setVal(user_data)

    obj.cmdtype = cmdtype
    this.request_map.set(user_data, obj)

    //开始升级
    var d = request.serializeBinary()
    socket.send(wrapWithXhumanoidFrame(d))
  }

  startUpload(file, obj) {
    var that = this
    obj.task = 'VERSION_UPLOAD_FILE'
    this.openSocket(obj, {
      onopen: function (socket, obj) {
        that.readFile(socket, file, obj ? obj : {})
      }
    })
  }

  startUpgrade(obj) {
    var that = this
    obj.task = 'VERSION_UPGRAD_ING'
    this.openSocket(obj, {
      onopen: function (socket, obj) {
        // that.sendRequestCheckStatus(socket, obj);
        that.sendRequestStartUpgrade(socket, obj)
      }
    })
  }
}

export default VersionUpgrade
