<template>
  <div class="content flex-space-between">
    <!-- 左侧版本列表 -->
    <div
      class="left flex-direction-column"
      :class="{ 'full-width': !showRight }"
    >
      <div
        class="g-page-container-with-header"
        v-for="(item, index) in sortedVersionData"
        :key="item.devid"
        :class="{ selected: selectedItemId === item.devid }"
      >
        <div class="container-header flex-space-between">
          <span class="title">{{ item.devdesp?.toUpperCase() }}</span>
          <div
            class="g-button"
            :class="[!item.enableUpgrade || isItemBusy(item) ? 'disabled' : '']"
            @click="handleUpgradeClick(item, index)"
          >
            {{ getItemStatusText(item) }}
          </div>
        </div>
        <div class="container-content">
          <div
            class="g-kv-pair"
            v-for="(label, key) in displayLabels"
            :key="key"
          >
            <div class="label">{{ label }}</div>
            <div class="value">{{ getDisplayValue(item, key) }}</div>
          </div>
        </div>
      </div>
    </div>

    <!-- 右侧上传区 -->
    <div v-if="showRight" class="right g-page-container">
      <div class="upload">
        <div
          class="g-button upload-btn"
          :class="{ disabled: isUploadingOrUpgrading }"
          @click="triggerFileUpload"
        >
          上传文件
          <img src="@/assets/img/upload/LogoLittle.png" class="upload-icon" />
        </div>
        <div
          class="upload-area"
          :class="{ disabled: isUploadingOrUpgrading }"
          @click="triggerFileUpload"
          @dragover.prevent
          @drop.prevent="handleFileDrop"
        >
          <img src="@/assets/img/upload/LogoBig.png" class="upload-big-icon" />
          <div class="el-upload__text">
            点击"上传文件"选择文件或将文件拖拽到此区域，以升级
            {{ selectedDevDesp }}
            (文件格式必须为.tar.gz)
          </div>
          <input
            type="file"
            ref="fileInput"
            style="display: none"
            @change="handleFileSelect"
          />
        </div>
      </div>
      <div class="g-table">
        <div class="cell flex-space-between header">
          <div class="name bg filename">文件名</div>
          <div class="name bg filesize">大小</div>
          <div class="name bg filestatus">状态</div>
          <div class="name bg fileaction">操作</div>
        </div>
        <div
          v-for="(file, idx) in uploadedFiles"
          :key="idx"
          class="cell flex-space-between file-row"
        >
          <el-tooltip :content="file.name" placement="top" :show-after="300">
            <div class="name filename">
              {{ truncateFileName(file.name, 12) }}
            </div>
          </el-tooltip>
          <div class="name filesize">{{ file.size }}</div>
          <div class="name filestatus status">
            <img :src="getStatusIcon(file.status)" class="status-icon" />
            <span :class="{ 'error-text': file.status === 'error' }">
              {{ getStatusText(file.status, file.percent, file.task) }}
            </span>
          </div>
          <div class="name fileaction action">
            <div
              class="g-button"
              :style="{
                visibility: getActionText(file.status, file.task)
                  ? 'visible'
                  : 'hidden'
              }"
              @click="handleFileAction(file)"
            >
              {{ getActionText(file.status, file.task) }}
            </div>
          </div>
        </div>

        <div v-if="uploadedFiles.length">
          <div class="button-with-status">
            <!-- 上传升级单按钮逻辑控制 -->
            <div
              class="g-button"
              :class="buttonClass"
              @click="handleButtonClick"
            >
              {{ buttonText }}
            </div>
            <!-- 升级状态label -->
            <div
              class="upgrade-status-text"
              v-if="uploadedFiles[0]?.status === 'upgrading'"
            >
              升级状态：{{ uploadedFiles[0].upgradeStatus || '未知' }}
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, watch } from 'vue'
import { storeToRefs } from 'pinia'
import { useWslStore } from '@/store/modules/ws.js'
import { useCommand } from '@/hooks/useCommand.js'
import { ElMessage } from 'element-plus'
import { useSortData } from '@/hooks/useSortData'

import VersionUpgrade from '@/utils/version_upgrade.js'
const uploadCache = ref({}) // { 'deviceId': { files: [...], finished: true/false } }

const store = useWslStore()
const { received, isConnected } = storeToRefs(store)
const { sendGetStatusData } = useCommand(store)

const displayLabels = {
  devid: '设备ID',
  devname: '设备名称',
  version: '版本',
  releaseTime: '发布时间'
}

const versionData = computed(() => {
  const data = received.value?.statusData?.versionDataList
  if (!data || data.length === 0) {
    return [{ devid: '001', devdesp: '暂无版本' }]
  }
  return data
})

const sortedVersionData = useSortData(versionData, {
  key: 'devid',
  type: 'number',
  order: 'asc'
}).sortedData

const selectedItemId = ref(null)
const selectedDevDesp = ref('')
const showRight = ref(false)
const fileInput = ref(null)

const uploadedFiles = ref([])
const uploadFinished = ref(false)
const upgradeFinished = ref(false)
const currentItem = ref(null)

const getDisplayValue = (item, key) => item[key] || '-'
const truncateFileName = (name, n) =>
  name.length > n ? name.slice(0, n) + '…' : name

const getStatusIcon = (status) =>
  ({
    pending: require('@/assets/img/upload/uploadPend.png'),
    uploading: require('@/assets/img/upload/uploading.png'),
    upgrading: require('@/assets/img/upload/uploading.png'), // 用上传中图标
    paused: require('@/assets/img/upload/uploadPend.png'),
    success: require('@/assets/img/upload/uploadSuccess.png'),
    error: require('@/assets/img/upload/uploadError.png')
  }[status] || '')

const getStatusText = (status, pct, task) => {
  if (status === 'uploading') {
    return `上传中 ${pct || 0}%`
  } else if (status === 'upgrading') {
    return `升级中 ${pct || 0}%`
  } else {
    return {
      pending: '待上传',
      // success: '上传成功',
      success: task === 'upgrade' ? '升级成功' : '上传成功',
      error: task === 'upgrade' ? '升级失败' : '上传失败'
    }[status]
  }
}

const getActionText = (status, task) =>
  ({
    pending: '删除',
    success: '删除',
    error: task === 'upgrade' ? '重新升级' : '重新上传'
  }[status] || '')

//单按钮控制逻辑
const buttonText = computed(() => {
  const file = uploadedFiles.value[0]
  if (!file) return ''
  if (file.status === 'uploading') return '上传中'
  if (file.status === 'upgrading') return '升级中'
  if (file.status === 'success') return '开始升级'
  return '开始上传'
})

// const buttonDisabled = computed(() => {
//   const file = uploadedFiles.value[0]
//   return file?.status === 'uploading' || file?.status === 'upgrading'
// })
// const buttonDisabled = isUploadingOrUpgrading

const buttonClass = computed(() => {
  const file = uploadedFiles.value[0]
  if (!file) return ''
  if (file.status === 'uploading') return 'start-upload-btn disabled'
  if (file.status === 'upgrading') return 'start-upgrade-btn disabled'
  if (file.status === 'success') return 'start-upgrade-btn'
  return 'start-upload-btn'
})

function getItemStatusText(item) {
  if (!item.enableUpgrade) return '不可升级'
  if (currentItem.value?.devid !== item.devid) return '可升级'

  const status = uploadedFiles.value[0]?.status
  const task = uploadedFiles.value[0]?.task

  if (status === 'uploading' && task === 'upload') return '上传中'
  if (status === 'upgrading' && task === 'upgrade') return '升级中'
  return '可升级'
}

function handleButtonClick() {
  const file = uploadedFiles.value[0]
  if (!file || isUploadingOrUpgrading.value) return
  if (file.status === 'success') {
    submitUpgrade()
  } else {
    submitUpload()
  }
}

const socketHostUrl =
  process.env.NODE_ENV === 'development'
    ? process.env.VUE_APP_WS_URL.replace('/status', '')
    : `ws://${window.location.hostname}:7123`

// 左侧卡片状态判断：判断当前 item 是否正在上传/升级
function isItemBusy(item) {
  if (currentItem.value?.devid !== item.devid) return false
  const file = uploadedFiles.value[0]
  return file?.status === 'uploading' || file?.status === 'upgrading'
}

//上传区域相关状态判断：是否正在上传/升级
const isUploadingOrUpgrading = computed(() => {
  const file = uploadedFiles.value[0]
  return file?.status === 'uploading' || file?.status === 'upgrading'
})

function handleUpgradeClick(item, index) {
  if (!item.enableUpgrade || isItemBusy(item)) return
  handleUpgrade(item, index)
}

function handleUpgrade(item, index) {
  selectedItemId.value = item.devid
  selectedDevDesp.value = item.devdesp || ''
  showRight.value = true
  currentItem.value = { ...item, index }

  // 初始化文件、上传完成、升级完成状态
  const cached = uploadCache.value[item.devid]
  if (cached) {
    uploadedFiles.value = JSON.parse(JSON.stringify(cached.files || []))
    uploadFinished.value = cached.uploadFinished || false
    upgradeFinished.value = cached.upgradeFinished || false
  } else {
    uploadedFiles.value = []
    uploadFinished.value = false
    upgradeFinished.value = false
  }
}

// 在上传成功/删除等地方更新缓存：
function updateUploadCache(devid) {
  uploadCache.value[devid] = {
    files: JSON.parse(JSON.stringify(uploadedFiles.value)), // 深拷贝确保响应式一致性
    uploadFinished:
      uploadedFiles.value[0]?.task === 'upload' &&
      uploadedFiles.value[0]?.status === 'success',
    upgradeFinished:
      uploadedFiles.value[0]?.task === 'upgrade' &&
      uploadedFiles.value[0]?.status === 'success'
  }
}

function triggerFileUpload() {
  fileInput.value.click()
}

function isValidFileType(file) {
  return file.name.endsWith('.tar.gz')
}

//上传文件-方式1：选择
function handleFileSelect(e) {
  const selected = Array.from(e.target.files)
  for (let f of selected) {
    if (!isValidFileType(f)) {
      ElMessage.error('只能上传 .tar.gz 文件')
      continue
    }
    uploadedFiles.value = [
      {
        name: f.name,
        raw: f,
        size: `${(f.size / 1024 / 1024).toFixed(2)}MB`,
        status: 'pending',
        percent: 0
      }
    ]
  }
  updateUploadCache(currentItem.value.devid)
}

//上传文件-方式2：拖拽
function handleFileDrop(e) {
  const dropped = Array.from(e.dataTransfer.files)
  for (let f of dropped) {
    if (!isValidFileType(f)) {
      ElMessage.error('只能上传 .tar.gz 文件')
      continue
    }
    uploadedFiles.value = [
      {
        name: f.name,
        raw: f,
        size: `${(f.size / 1024 / 1024).toFixed(2)}MB`,
        status: 'pending',
        percent: 0
      }
    ]
  }
  updateUploadCache(currentItem.value.devid)
}

function handleFileAction(file) {
  if (file.status === 'error') {
    file.percent = 0
    file.upgradeStatus = ''

    if (file.task === 'upgrade') {
      // 升级失败，重新升级
      file.status = 'success'
      // 立刻重新开始升级
      submitUpgrade()
    } else {
      // 上传失败，重新上传
      file.status = 'pending'
      // 立刻重新开始上传
      submitUpload()
    }
    return
  }

  // 允许删除
  if (file.status === 'pending' || file.status === 'success') {
    uploadedFiles.value = uploadedFiles.value.filter((f) => f !== file)
    updateUploadCache(currentItem.value.devid)
  }
}

function submitUpload() {
  const file = uploadedFiles.value[0]
  if (!file) return

  file.task = 'upload'
  file.status = 'uploading'
  uploadFinished.value = false

  const uploader = new VersionUpgrade()
  uploader.setSocketUrl(`${socketHostUrl}/version/upgrade`)

  const uploadObj = {
    devid: currentItem.value.devid,
    devname: currentItem.value.devname,
    package_name: file.name,
    task: 'VERSION_UPLOAD_FILE',
    debug: true, // 可选项
    index: currentItem.value.index,
    onEventUploadPercent: (obj, data) => {
      file.percent = data.percent
    },
    onEventUploadFinished: () => {
      file.status = 'success'
      uploadFinished.value = true
      ElMessage.success('上传完成')
      //缓存
      updateUploadCache(currentItem.value.devid)
    },
    onEventErrorMessage: (obj, resp) => {
      file.status = 'error'
      file.task = 'upload'
      ElMessage.error(resp?.errorMessage || '上传失败')
      //缓存
      updateUploadCache(currentItem.value.devid)
    }
  }

  uploader.startUpload(file.raw, uploadObj)
}

function submitUpgrade() {
  const file = uploadedFiles.value[0]
  if (!file || file.status !== 'success') {
    ElMessage.warning('请先完成上传')
    return
  }

  // ElMessage.info('升级已开始，请耐心等待...')
  file.status = 'upgrading'
  file.task = 'upgrade'
  file.percent = 0
  file.upgradeStatus = ''

  const upgradeUploader = new VersionUpgrade()
  upgradeUploader.setSocketUrl(`${socketHostUrl}/version/upgrade`)

  const upgradeObj = {
    devid: currentItem.value.devid,
    devname: currentItem.value.devname,
    package_name: file.name,
    task: 'VERSION_UPGRAD_ING',
    debug: true,
    onEventUpgradeProgress: (obj, data) => {
      file.percent = Math.round(data.percent || 0)
      file.upgradeStatus = data.upgradeStatus || ''
    },
    onUpgradePartialSuccess: () => {
      file.status = 'success'
      upgradeFinished.value = true
      ElMessage({
        type: 'success',
        message: '升级已完成，需要重启机器',
        duration: 0,
        showClose: true
      })
      updateUploadCache(currentItem.value.devid)
    },
    onUpgradeFullSuccess: () => {
      file.status = 'success'
      upgradeFinished.value = true
      ElMessage({
        type: 'success',
        message: '升级已全部完成',
        duration: 0,
        showClose: true
      })
      updateUploadCache(currentItem.value.devid)
    },
    onEventErrorMessage: (obj, resp) => {
      file.status = 'error'
      file.task = 'upgrade'
      file.upgradeStatus = resp?.versionUpdateResponse?.upgradeStatus || ''
      ElMessage({
        type: 'error',
        message: resp?.errorMessage || '升级失败',
        duration: 0,
        showClose: true
      })
      //缓存
      updateUploadCache(currentItem.value.devid)
    }
    // onEventAlertMessage: (obj, resp) => {
    //   if (resp?.versionUpdateResponse?.alertMessage) {
    //     ElMessage({
    //       type: resp.versionUpdateResponse.alertType || 'info',
    //       message: resp.versionUpdateResponse.alertMessage
    //     })
    //   }
    // }

    // onEventLogMessage: (obj, resp) => {
    //   const msg = resp?.versionUpdateResponse?.logMessage
    //   const type = resp?.versionUpdateResponse?.logType || 'info'
    //   if (msg) {
    //     ElNotification({
    //       title: '升级日志',
    //       message: msg,
    //       type,
    //       duration: 2000
    //     })
    //   }
    // }
  }
  upgradeUploader.startUpgrade(upgradeObj)
}

// alert弹窗提醒
watch(
  () => received.value?.versionUpdateResponse,
  (resp) => {
    // 有提示时才弹出弹窗
    if (resp?.alertType && resp?.alertMessage) {
      ElMessage({
        type: resp.alertType || 'info',
        message: resp.alertMessage,
        duration: 3000
      })
    }
  }
)

watch(
  () => isConnected.value,
  (conn) => conn && sendGetStatusData('version'),
  { immediate: true }
)
</script>

<style lang="less" scoped>
.el-message {
  max-width: 500px !important;
  white-space: pre-wrap;
}

.content {
  align-items: flex-start;

  .g-button.disabled {
    background-color: #dcdfe6;
    color: #86898f;
    cursor: not-allowed;
    pointer-events: none;
    opacity: 0.6;
  }

  .upload-area.disabled {
    pointer-events: none;
    opacity: 0.6;
    cursor: not-allowed;
  }

  .left {
    width: 100%;
    transition: width 0.3s ease;

    &.full-width {
      width: 100%;
    }
  }

  .right {
    flex: 2;
    margin-left: 20px;
    padding: 20px;

    .button-with-status {
      display: flex;
      align-items: center;
      gap: 12px;

      .upgrade-status-text {
        font-size: 14px;
        color: #606266;
      }
    }

    .start-upload-btn,
    .start-upgrade-btn {
      margin: 10px 0;
    }

    .upload {
      .upload-btn {
        .upload-icon {
          width: 20px;
          height: 20px;
          margin-left: 5px;
        }
      }

      .upload-area {
        border: 2px dashed #d9d9d9;
        border-radius: 6px;
        cursor: pointer;
        text-align: center;
        padding: 20px;
        margin-top: 10px;
        height: 180px;
        display: flex;
        flex-direction: column;
        justify-content: center;
        align-items: center;

        .upload-big-icon {
          width: 50px;
          height: 50px;
          margin-bottom: 10px;
        }

        .el-upload__text {
          color: #606266;
          font-size: 14px;
        }
      }
    }

    .g-table {
      .name {
        &.filename {
          width: 5rem;
          // white-space: nowrap;
        }
        &.filesize,
        &.filestatus,
        &.fileaction {
          width: 5rem;
        }

        &.status {
          display: flex;
          align-items: center;
          justify-content: flex-start;

          .status-icon {
            width: 16px;
            height: 16px;
            margin-right: 5px;
          }

          .error-text {
            color: #ea0000;
          }
        }
      }
    }
  }
}
</style>
