export function useXhumanoidFrame() {
  const wrapWithXhumanoidFrame = (data) => {
    const xhumanHeader = new TextEncoder().encode('XHUMANOID') // 帧头
    const xhumanLength = new Uint8Array(4)
    new DataView(xhumanLength.buffer).setUint32(0, data.length, false) // 大端
    const xhumanTail = new Uint8Array([0x21]) // 帧尾 “!”

    const finalBuffer = new Uint8Array(
      xhumanHeader.length + 4 + data.length + 1
    )
    finalBuffer.set(xhumanHeader, 0)
    finalBuffer.set(xhumanLength, xhumanHeader.length)
    finalBuffer.set(data, xhumanHeader.length + 4)
    finalBuffer.set(xhumanTail, xhumanHeader.length + 4 + data.length)
    return finalBuffer
  }

  return {
    wrapWithXhumanoidFrame
  }
}
